const FAQS = [
  { q: "What makes a strong password?", a: "A strong password has at least 12-16 characters and includes uppercase letters, lowercase letters, numbers, and symbols. Avoid dictionary words, personal information (birthdays, names), keyboard patterns like 'qwerty', and common passwords like '123456' or 'password'. According to NIST guidelines, length is the most critical factor - a 20-character passphrase is stronger than an 8-character complex password." },
  { q: "How often should I change my password?", a: "Current NIST guidelines (NIST SP 800-63B) no longer recommend routine forced password changes. Mandatory periodic changes often lead to weaker passwords as users make predictable increments. Instead, change passwords when you suspect compromise, when a service you use has a data breach, or when you've shared a password. Use haveibeenpwned.com to check for breaches." },
  { q: "Should I use a password manager?", a: "Yes - password managers are the single best security improvement most people can make. They generate and store unique, complex passwords for every account. You only need to remember one strong master password. Reputable options include Bitwarden (open source, free), 1Password, Dashlane, and Apple/Google's built-in password managers. Never reuse passwords across sites." },
  { q: "What is entropy in password security?", a: "Entropy measures unpredictability in bits - higher entropy means exponentially more combinations to guess. Entropy (bits) = log-et size^length). A 16-char password with all 95 printable ASCII characters: log-) - 105 bits of entropy. That's over 40 octillion times harder to brute-force than an 8-character lowercase-only password (~41 bits)." },
  { q: "How long would it take to crack my password?", a: "Modern GPUs can attempt 100+ billion MD5 hashes per second. An 8-character lowercase password (26^8 - 208 billion combos) falls in under 2 seconds. A 12-character password with all character types (95^12 - 540 trillion trillion combos) would take billions of years. Adding just 4 characters to a password makes it astronomically harder to crack." },
  { q: "Is it safe to use a password generator?", a: "Yes - this generator uses the Web Cryptography API (crypto.getRandomValues()) which is cryptographically secure and built into all modern browsers. It generates randomness from the OS-level entropy source (same level used for TLS). The password is generated entirely in your browser - it is never transmitted anywhere." },
  { q: "What is a passphrase and is it better than a password?", a: "A passphrase is a sequence of random words (e.g., 'correct-horse-battery-staple'). A 4-word passphrase from a 7,000-word list has ~50 bits of entropy - similar to a random 8-character complex password but far more memorable. NIST recommends passphrases for human-remembered credentials. Random character passwords are better for password manager storage." },
  { q: "What characters should I avoid in passwords?", a: "Some systems can't handle certain characters. Commonly problematic: spaces (may be trimmed), quotes (SQL injection risk in poorly coded sites), and non-ASCII characters (encoding issues). For maximum compatibility, use uppercase (A-Z), lowercase (a-z), digits (0-9), and safe symbols: !@#$%^&*_+-=. This calculator uses exactly these safe symbols." },
];

const ENTROPY_TABLE = [
  ["8 chars, lowercase only", "26", "~41 bits", "< 1 second (GPU)"],
  ["8 chars, mixed case + digits", "62", "~48 bits", "< 1 hour"],
  ["12 chars, mixed case + digits", "62", "~71 bits", "Centuries"],
  ["16 chars, all character types", "95", "~105 bits", "Billions of years"],
  ["20 chars, all character types", "95", "~131 bits", "Heat death of universe"],
  ["4-word passphrase", "7,776", "~51 bits", "Decades (offline)"],
];

function generatePassword(length: number, upper: boolean, lower: boolean, numbers: boolean, symbols: boolean): string {
  const uppers = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  const lowers = "abcdefghijklmnopqrstuvwxyz";
  const nums = "0123456789";
  const syms = "!@#$%^&*()_+-=[]{}|;:,.<>?";
  let charset = "";
  if (upper) charset += uppers;
  if (lower) charset += lowers;
  if (numbers) charset += nums;
  if (symbols) charset += syms;
  if (!charset) charset = lowers;
  const arr = new Uint32Array(length);
  crypto.getRandomValues(arr);
  return Array.from(arr).map(v => charset[v % charset.length]).join("");
}

export default function PasswordGenerator() {
  const [length, setLength] = useState(16);
  const [upper, setUpper] = useState(true);
  const [lower, setLower] = useState(true);
  const [numbers, setNumbers] = useState(true);
  const [symbols, setSymbols] = useState(true);
  const [password, setPassword] = useState(() => generatePassword(16, true, true, true, true));
  const [copied, setCopied] = useState(false);

  const generate = useCallback(() => {
    setPassword(generatePassword(length, upper, lower, numbers, symbols));
  }, [length, upper, lower, numbers, symbols]);

  const copy = () => { navigator.clipboard.writeText(password); setCopied(true); setTimeout(() => setCopied(false), 2000); };

  const charsetSize = (upper ? 26 : 0) + (lower ? 26 : 0) + (numbers ? 10 : 0) + (symbols ? 30 : 0) || 26;
  const entropy = Math.log2(Math.pow(charsetSize, length));
  const strength = [upper, lower, numbers, symbols].filter(Boolean).length + (length >= 16 ? 1 : 0) + (length >= 20 ? 1 : 0);
  const strengthLabel = strength <= 2 ? "Weak" : strength <= 4 ? "Medium" : "Strong";
  const strengthColor = strength <= 2 ? "bg-red-500" : strength <= 4 ? "bg-amber-500" : "bg-emerald-500";

  return (
    <>
      <SEOHead
        title="Free Password Generator Online - Generate Strong Secure Passwords Instantly | CalcHive"
        description="Free online password generator. Generate strong cryptographically secure passwords with customizable options instantly. 100% free for everyone, no signup required, works on all devices."
        canonical="/password-generator"
        keywords="free password generator, strong password generator free online, secure password generator free, random password generator free, free password creator online"
        category="Security Tools"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800/50 px-3 py-1 rounded-full mb-4 inline-block">Tools</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Password Generator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free password generator to create strong passwords with customizable options. This strong password generator free online also works as a secure password generator free, random password generator free, and free password creator online.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6">
            <SliderInput id="pw-length" label="Password Length" value={length} min={6} max={64} step={1} onChange={v => { setLength(v); setPassword(generatePassword(v, upper, lower, numbers, symbols)); }} testId="input-length" helpText={`${length} characters - ~${entropy.toFixed(0)} bits of entropy`} />
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-6">
            {[
              { label: "Uppercase (A-Z)", val: upper, onToggle: (v: boolean) => { setUpper(v); setPassword(generatePassword(length, v, lower, numbers, symbols)); } },
              { label: "Lowercase (a-z)", val: lower, onToggle: (v: boolean) => { setLower(v); setPassword(generatePassword(length, upper, v, numbers, symbols)); } },
              { label: "Numbers (0-9)", val: numbers, onToggle: (v: boolean) => { setNumbers(v); setPassword(generatePassword(length, upper, lower, v, symbols)); } },
              { label: "Symbols (!@#)", val: symbols, onToggle: (v: boolean) => { setSymbols(v); setPassword(generatePassword(length, upper, lower, numbers, v)); } },
            ].map(({ label, val, onToggle }) => (
              <label key={label} className={`flex items-center gap-2 p-3 rounded-xl border cursor-pointer transition-all ${val ? "bg-accent border-primary/40" : "border-border"}`}>
                <input type="checkbox" checked={val} onChange={e => onToggle(e.target.checked)} className="accent-primary" />
                <span className="text-xs font-medium text-foreground">{label}</span>
              </label>
            ))}
          </div>
          <motion.div key={password} initial={{ opacity: 0.7 }} animate={{ opacity: 1 }} transition={{ duration: 0.2 }}>
            <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-5 mb-4 shadow-lg">
              <div className="flex items-center justify-between gap-3">
                <p className="font-mono text-white text-base sm:text-lg font-bold break-all flex-1" data-testid="result-password">{password}</p>
                <div className="flex gap-2 flex-shrink-0">
                  <button onClick={copy} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 transition-colors text-white" aria-label="Copy password"><Copy className="w-4 h-4" /></button>
                  <button onClick={generate} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 transition-colors text-white" aria-label="Generate new password"><RefreshCw className="w-4 h-4" /></button>
                </div>
              </div>
              {copied && <p className="text-xs text-emerald-400 mt-2">Copied to clipboard!</p>}
            </div>
            <div className="flex items-center gap-3">
              <div className="flex-1 h-2 bg-muted rounded-full overflow-hidden">
                <div className={`h-full rounded-full transition-all ${strengthColor}`} style={{ width: `${Math.min(100, (strength / 6) * 100)}%` }} />
              </div>
              <span className="text-sm font-semibold text-foreground">{strengthLabel} - {entropy.toFixed(0)} bits</span>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Generate a Strong Secure Password for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Entropy measures how unpredictable a password is. Each bit of entropy doubles the number of guesses required. Modern cryptographic security standards recommend at least 80 bits of entropy for high-value accounts. This generator with default settings (16 chars, all types) produces ~105 bits.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Entropy (bits) = log2(charset size ^ password length)</p>
            <p className="text-xs text-muted-foreground mt-2">Current: log2({charsetSize}^{length}) = {entropy.toFixed(1)} bits</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What Makes a Password Cryptographically Secure</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Password Type", "Charset Size", "Entropy", "GPU Crack Time (100B/sec)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {ENTROPY_TABLE.map(([type, charset, ent, time]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{charset}</td>
                    <td className="py-2.5 px-4 text-slate-600 dark:text-slate-400 font-bold">{ent}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{time}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Password Creator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free security tool on any device to create strong passwords quickly without storing your results or requiring signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/password-generator" headingLevel="h3" />
      </main>
    </>
  );
}


